Create a C++ program that reads in a CSV file containing a list of student names and their grades for a particular course. The program should calculate the average grade for each student and output the results to an Excel table. Additionally, the program should identify the student with the highest average grade and output their name and grade to a JSON data file. Can you provide a solution for this programming exercise?

### Response:
Sure, here's a solution to your programming exercise:
```c++
#include 
#include 
#include 
#include 
#include 
#include 
#include 
using json = nlohmann::json;
struct Student {
 std::string name;
 std::vector grades;
 double average_grade;
};
std::vector read_csv_file(const std::string& filename) {
 std::vector students;
 std::ifstream file(filename);
 if (!file.is_open()) {
 std::cerr << "Error: Could not open file " << filename << std::endl;
 return students;
 }
 std::string line;
 while (std::getline(file, line)) {
 std::stringstream ss(line);
 std::string name;
 std::getline(ss, name, ',');
 std::vector grades;
 double grade;
 while (ss >> grade) {
 grades.push_back(grade);
 if (ss.peek() == ',') {
 ss.ignore();
 }
 }
 students.push_back({name, grades, 0.0});
 }
 file.close();
 return students;
}
void calculate_average_grades(std::vector& students) {
 for (auto& student : students) {
 double sum = 0.0;
 for (const auto& grade : student.grades) {
 sum += grade;
 }
 student.average_grade = sum / student.grades.size();
 }
}
void write_excel_table(const std::vector& students) {
 std::ofstream file("output.xlsx");
 file << "NametAverage Graden";
 for (const auto& student : students) {
 file << student.name << "t" << std::fixed << std::setprecision(2) << student.average_grade << "n";
 }
 file.close();
}
void write_json_data(const std::vector& students) {
 auto max_grade_student = std::max_element(students.begin(), students.end(),
 [](const Student& a, const Student& b) {
 return a.average_grade < b.average_grade;
 });
 json data = {
 {"name", max_grade_student->name},
 {"average_grade", max_grade_student->average_grade}
 };
 std::ofstream file("output.json");
 file << std::setw(4) << data << std::endl;
 file.close();
}
int main() {
 auto students = read_csv_file("input.csv");
 if (students.empty()) {
 return 1;
 }
 calculate_average_grades(students);
 write_excel_table(students);
 write_json_data(students);
 return 0;
}
```
